function defaultEngine() {
    return {
        state: 'initialized',
        simulation_time: new Date().toISOString(),
        seed: Number(env.get('BASE_SEED') || 12345),
        acceleration: Number(env.get('SPEED_FACTOR') || 1),
        registered_entities: 0,
        last_transition_at: Date.now()
    };
}
const engine = flow.get('engine') || defaultEngine();
const body = (msg.payload && typeof msg.payload === 'object') ? msg.payload : {};

if (typeof body.start_time === 'string' && body.start_time.length > 0) {
    engine.simulation_time = body.start_time;
}

let message;
if (engine.state === 'paused') {
    engine.state = 'running';
    message = 'Simulation resumed';
} else if (engine.state === 'running') {
    message = 'Simulation already running';
} else {
    engine.state = 'running';
    if (!engine.simulation_time) {
        engine.simulation_time = new Date().toISOString();
    }
    message = 'Simulation started';
}

engine.last_transition_at = Date.now();
flow.set('engine', engine);

const persistMsg = { payload: JSON.stringify(engine, null, 2),
                     filename: '/data/sim-state/state.json' };
msg.payload = {
    status: 'started',
    message: message,
    simulation_time: engine.simulation_time
};
msg.statusCode = 200;
return [msg, persistMsg];

